    @Query(value = "SELECT\n\trh_nomina_liquidacion.FechaR AS fecha  \n                                       ,\n\trh_nomina_liquidacion_detalle.Id_Liquidacion AS idLiquidacion\n                                       ,\n\trh_nomina_liquidacion_detalle.Id_PersonaC AS idPersona\n                                       ,\n\tg_persona.`NoDocumento` AS noDocumento\n                                       ,\n\trh_nomina_liquidacion_detalle.`Consecutivo` \n                                       ,\n\tCONCAT(g_persona.Nombre1,\n\t' ' \n                                       ,\n\tg_persona.Nombre2,\n\t' '\n                                       ,\n\tg_persona.Apellido1,\n\t' '\n                                       ,\n\tg_persona.Apellido2) AS empleado\n                                       ,\n\t`rh_tipo_persona_cargon`.`FechaIngreso`\n                                       ,\n\tDATEDIFF(CURDATE(), `rh_tipo_persona_cargon`.`FechaIngreso`) AS tiempoLaborado\n                                       ,\n\t`rh_nomina_liquidacion`.`Id_Periodo` AS idPeriodo ,\n\trh_nomina_liquidacion_detalle.cune ,\n\trh_nomina_liquidacion_detalle.keyDian\n\t, (sum(rh_nomina_liquidacion_detalle.VDevengado) - sum(rh_nomina_liquidacion_detalle.VDeducido )) valorTotalNomina, g_persona.Correo correoElectronico, rh_nomina_liquidacion.fechaPago\nFROM\n\trh_nomina_liquidacion_detalle\nLEFT JOIN `rh_tipo_persona_cargon` \n                                           ON\n\t(rh_nomina_liquidacion_detalle.Id_PersonaC = `rh_tipo_persona_cargon`.Id)\nLEFT JOIN `g_persona`\n                                           ON\n\t(`rh_tipo_persona_cargon`.`Id_Persona` = `g_persona`.Id)\nINNER JOIN rh_nomina_liquidacion \n                              ON\n\t(rh_nomina_liquidacion.Id = rh_nomina_liquidacion_detalle.Id_Liquidacion)\nWHERE\n\t(rh_nomina_liquidacion_detalle.Id_Liquidacion =:id )\nGROUP BY\n\tg_persona.`NoDocumento`\norder by \templeado asc", nativeQuery = true)
    List<EmpleadoPorNomina> listaEmpleados(@Param("id") Integer num);

    @Query(value = "SELECT \n                          CONCAT( \n                            g_persona.`Id_TipoIdentificacion`, \n                            ' ', \n                            g_persona.NoDocumento \n                          ) AS documento, \n                          CONCAT( \n                            g_persona.Apellido1, \n                            ' ',\n                            g_persona.Apellido2, \n                            ' ',\n                            g_persona.Nombre1, \n                            ' ', \n                            g_persona.Nombre2 \n                          ) AS empleado, \n                          rh_nomina_liquidacion_detalle.Id_PersonaC AS idPersonaC, \n                          rh_tipo_cargo.Nbre AS cargo, \n                          rh_nomina_conceptos.Nbre AS concepto, \n                          sum(rh_nomina_liquidacion_detalle.VDevengado) AS devengado, \n                          sum(rh_nomina_liquidacion_detalle.VDeducido) AS deducido, \n                          sum(rh_nomina_liquidacion_detalle.TValorE) AS valorEmpresa, \n                          rh_nomina_liquidacion_detalle.Id_Tercero AS idTercero, \n                          `rh_tipo_persona_cargon`.Id AS idTipoCargo, \n                          rh_nomina_conceptos.Id AS idConcepto, \n                          ATotal.NetoP AS netoP, \n                          g_persona.NoDocumento AS terceroDocumento, \n                          rh_tipo_clasificacion_conceptonomina.Nbre AS clasificacionConcepto, \n                          rh_tipo_clasificacion_conceptonomina.Id AS idClasificacionConcepto, \n                          rh_nomina_conceptos.CSalario AS cSalario, \n                          rh_nomina_liquidacion_detalle.Id_ConceptoCN AS idConceptoCN, \n                         -- rh_nomina_liquidacion_detalle.I\n                         1 AS idCGestion, \n                          cc_terceros.`RazonSocial` AS terceroP , \n                          rh_nomina_conceptos.Id_ClasificacionNominaE AS idClasificacionNominaE , \n                          `rh_nomina_liquidacion_detalle`.`Cantidad` AS cantidad ,\n                           rh_nomina_conceptos.`Valor` AS porcentajeValor \n                        FROM \n                          rh_nomina_liquidacion_detalle \n                          INNER JOIN rh_nomina_liquidacion \n                            ON ( \n                              rh_nomina_liquidacion_detalle.Id_Liquidacion = rh_nomina_liquidacion.Id \n                            ) \n                          INNER JOIN rh_nomina_concepto_unidadf \n                            ON ( \n                              rh_nomina_liquidacion_detalle.Id_ConceptoCN = rh_nomina_concepto_unidadf.Id \n                            ) \n                          INNER JOIN `rh_tipo_persona_cargon`\n                            ON ( \n                              rh_nomina_liquidacion_detalle.Id_PersonaC = `rh_tipo_persona_cargon`.Id \n                            ) \n                          INNER JOIN rh_nomina_conceptos \n                            ON ( \n                              rh_nomina_concepto_unidadf.Id_ConceptosN = rh_nomina_conceptos.Id \n                            ) \n                           INNER JOIN g_persona \n                            ON ( \n                             `rh_tipo_persona_cargon`.`Id_Persona`= g_persona.Id \n                            ) \n                            INNER JOIN `rh_unidadf_cargo`\n                            ON(`rh_tipo_persona_cargon`.`Id_unidadf_cargo` = `rh_unidadf_cargo`.`Id`)\n                          INNER JOIN rh_tipo_cargo \n                            ON ( \n                              `rh_unidadf_cargo`.`Id_Cargo` = rh_tipo_cargo.Id \n                            ) \n                          INNER JOIN rh_tipo_clasificacion_conceptonomina \n                            ON ( \n                              rh_nomina_conceptos.Id_Clasificacion = rh_tipo_clasificacion_conceptonomina.Id \n                            ) \n                          INNER JOIN cc_terceros\n                            ON ( rh_nomina_liquidacion_detalle.Id_Tercero = cc_terceros.Id ) \n                          INNER JOIN `cc_unidad_funcional` \n                            ON ( \n                              rh_nomina_concepto_unidadf.Id_UnidaFC = `cc_unidad_funcional`.Id \n                            )\n                          INNER JOIN\n                            (SELECT\n                              (SUM(VDevengado) - SUM(VDeducido)) AS NetoP, \n                              Id_PersonaC \n                            FROM \n                              rh_nomina_liquidacion_detalle \n                            WHERE (Id_Liquidacion =:id  AND rh_nomina_liquidacion_detalle.Id_PersonaC =:idPersona\n                            ) \n                            GROUP BY Id_Liquidacion, \n                              Id_PersonaC) ATotal \n                            ON ( \n                              ATotal.Id_PersonaC = `rh_tipo_persona_cargon`.Id \n                            )\n                        WHERE rh_nomina_liquidacion.Id =:id AND rh_nomina_liquidacion_detalle.Id_PersonaC =:idPersona\n   group by  rh_nomina_conceptos.Id_ClasificacionNominaE HAVING(devengado>0 OR deducido>0 OR valorEmpresa>0)\n   ORDER BY Empleado ASC,rh_nomina_conceptos.Id ASC", nativeQuery = true)
    List<ConceptoPorEmpleado> nominaPorEmpleado(@Param("id") Integer num, @Param("idPersona") Integer num2);

    @Query(value = "SELECT\n               g_pais.`Codigo` AS pais\n               , g_municipio.`Id_Dpto` AS departamento\n               , g_municipio.Id AS municipio\n               , 'es' AS idioma\n            FROM\n               g_ips\n               INNER JOIN g_municipio \n                   ON (g_ips.`Id_Municipio`= `g_municipio`.Id)\n               INNER JOIN g_departamento \n                   ON (g_municipio.`Id_Dpto` = g_departamento.Id)\n               INNER JOIN g_pais \n                   ON (g_departamento.`CodPais` = g_pais.Id)", nativeQuery = true)
    LugarDeGeneracion lugarDeGeneracion();

    @Query(value = "SELECT\n                `g_ips`.`Nbre` AS razonSocial\n                , `g_ips`.`DigitoVerificacion` AS dv\n                , `g_ips`.`Identificacion` AS nit\n                , `g_ips`.`Direccion` AS direccion\n                , `g_pais`.`Codigo` AS pais\n                , `g_municipio`.`Id_Dpto` AS departamentoEstado\n                , `g_municipio`.`Id` AS municipioCiudad\n                \n            FROM\n                `g_ips`\n                INNER JOIN `g_municipio` \n                    ON (`g_ips`.`Id_Municipio` = `g_municipio`.`Id`)\n                INNER JOIN `g_departamento` \n                    ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`)\n                INNER JOIN `g_pais` \n                    ON (`g_departamento`.`CodPais` = `g_pais`.`Id`)", nativeQuery = true)
    EmpleadorProyection getEmpleador();

    @Query(value = "SELECT\n                           `rh_tipo_trabajador`.`codigo` AS idTipoTrabajador\n                           , `rh_tercero_empleado_inf_laboral`.`SubTipoTrabajador` AS subTipoTrabajador\n                           , `rh_tercero_empleado_inf_laboral`.`AltoRiesgoPesion` AS altoRiesgoPension\n                           , `g_tipoidentificacion`.`Id_Dian` AS idTipoDocumento\n                           , `g_persona`.`NoDocumento` AS numeroDocumento\n                           , `g_persona`.`Apellido1` AS primerApellido\n                           , `g_persona`.`Apellido2` AS segundoApellido\n                           , `g_persona`.`Nombre1` AS primerNombre\n                           ,  IF(`g_persona`.`Nombre2`='',NULL,`g_persona`.`Nombre2`) AS otrosNombres\n                           , `g_pais`.`Codigo` AS lugarTrabajoPais\n                           , `g_departamento`.`Id` AS lugarTrabajoDepartamentoEstado\n                           , CONCAT(`g_municipio`.`Id`)  AS lugarTrabajoMunicipioCiudad\n                           , `rh_tipo_persona_cargon`.`SIntegral` AS salarioIntegral\n                           , `rh_tercero_empleado_inf_laboral`.`Id_TipoContrato` AS tipoContrato\n                           , `rh_tipo_persona_cargon`.`SalarioB` AS sueldo \n                           , `g_persona`.`NoDocumento`  AS `codigoTrabajador`\n                           , `rh_tipo_persona_cargon`.FormaDePago AS formaPago\n                           , `rh_tipo_persona_cargon`.MetodoDePago AS metodoPago\n                           , `cc_banco`.`Nbre` AS banco\n                           , `cc_tipo_cuenta`.`Nbre` AS `tipoCuenta`\n                           , `cc_cuentaxempresa`.`NCuenta` AS numeroCuenta\n                           , `rh_tercero_empleado_inf_laboral`.`Direccion` AS lugarTrabajoDireccion \n                       FROM\n                           `rh_tipo_persona_cargon`\n                           INNER JOIN `rh_tercero_empleado_inf_laboral` \n                               ON (`rh_tipo_persona_cargon`.`Id` = `rh_tercero_empleado_inf_laboral`.`Id_PersonaC`) AND (rh_tercero_empleado_inf_laboral.Estado = 1)\n                           INNER JOIN `g_municipio` \n                               ON (`rh_tercero_empleado_inf_laboral`.`Id_Municipio` = `g_municipio`.`Id`)\n                           INNER JOIN g_persona\n                               ON (`rh_tipo_persona_cargon`.`Id_Persona` = `g_persona`.`Id`)\n                           INNER JOIN `g_empresa`\n                               ON(`g_persona`.`NoDocumento` = `g_empresa`.`No_identificacion`) and (g_empresa.Estado=1)\n                           INNER JOIN `g_departamento` \n                               ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`)\n                           INNER JOIN `g_pais` \n                               ON (`g_departamento`.`CodPais` = `g_pais`.`Id`)\n                           INNER JOIN `cc_cuentaxempresa` \n                               ON (`cc_cuentaxempresa`.`Id_Empresa` = `g_empresa`.`Id`) and (cc_cuentaxempresa.Estado=1) and (cc_cuentaxempresa.EsPrincipal=1)\n                           INNER JOIN `cc_bancoxsucursal` \n                               ON (`cc_cuentaxempresa`.`Id_SucursalxBanco` = `cc_bancoxsucursal`.`Id`)\n                           INNER JOIN `cc_banco` \n                               ON (`cc_bancoxsucursal`.`Id_Banco` = `cc_banco`.`Id`)\n                           INNER JOIN `cc_tipo_cuenta` \n                               ON (`cc_cuentaxempresa`.`Id_TipoCuenta` = `cc_tipo_cuenta`.`Id`)\n                          INNER JOIN `g_tipoidentificacion`\n                               ON (`g_empresa`.`Id_TipoIdentificacion` = `g_tipoidentificacion`.`Id`) \n                          INNER JOIN `rh_tipo_trabajador`                           ON (`rh_tipo_trabajador`.`id` =  `rh_tercero_empleado_inf_laboral`.`Id_TipoTrabajador` )             WHERE (`rh_tipo_persona_cargon`.`Id` =:id)", nativeQuery = true)
    EmpleadoPagoProyection getEmpleadoPago(@Param("id") Integer num);

    @Query(value = "SELECT\n               `rh_tipo_persona_cargon`.`Id` AS idPersona\n               , g_persona.`NoDocumento` AS noDocumento\n               , CONCAT(g_persona.`Apellido1`, ' '\n               , g_persona.`Apellido2`, ' '\n               , g_persona.`Nombre1`, ' '\n               , g_persona.`Nombre2`) AS empleado\n               , `rh_tipo_persona_cargon`.`SalarioB` AS salario \n            FROM\n               `rh_tipo_persona_cargon`\n               INNER JOIN `g_persona` \n                   ON (`rh_tipo_persona_cargon`.`Id_Persona` = g_persona.`Id`)\n            WHERE (`rh_tipo_persona_cargon`.`Estado` =1 ) HAVING noDocumento like %:filtro% or empleado like %:filtro% ", nativeQuery = true)
    List<EmpleadosNomina> obtenerEmpleados(@Param("filtro") String str);

    @Query(value = "WITH  maestra AS (\nSELECT \n     CONCAT(DATE_FORMAT(`rh_nomina_novedades_detalle`.`fechaInicio`,'%x-%m-%d'),'T',`rh_nomina_novedades_detalle`.`HoraInicio`) AS horaInicio \n     ,CONCAT(DATE_FORMAT(`rh_nomina_novedades_detalle`.`fechaFin`,'%x-%m-%d'),'T', `rh_nomina_novedades_detalle`.`HoraFin`) AS horaFin \n     , `rh_nomina_novedades_detalle`.`fechaD` \n     , `rh_nomina_novedades_detalle`.`cantidad` \n     , `rh_nomina_conceptos`.`Valor` AS `porcentaje` \n     , `rh_nomina_conceptos`.`porcentajeDian` AS `porcentajeDian` \n     , DATE_FORMAT(`rh_nomina_novedades_detalle`.`fechaInicio`,'%x-%m-%d') AS fechaInicio \n     , DATE_FORMAT(`rh_nomina_novedades_detalle`.`fechaFin`,'%x-%m-%d') AS fechaFin \n     , rh_nomina_novedades.`id` \n     , `rh_nomina_conceptos`.`Id_ClasificacionNominaE` AS clasificacionNominaElectronica  \n       , `rh_nomina_novedades_detalle`.`valor`  \n       , rh_nomina_novedades_detalle.`idConcepto` idConcepto\n       , rh_nomina_novedades.`idPersonaCargo`\n       , rh_nomina_novedades_detalle.`idLiquidacionNomina`\n     , rh_nomina_novedades_detalle.`id` idDetalleNovedad\n      FROM \n     `rh_nomina_novedades`\n     INNER JOIN  `rh_nomina_novedades_detalle`  ON (`rh_nomina_novedades_detalle`.`idEncabezado` = `rh_nomina_novedades`.`id`) \n     INNER JOIN `rh_nomina_conceptos`  ON (`rh_nomina_novedades_detalle`.`idConcepto` = `rh_nomina_conceptos`.`Id`)  \n  WHERE (rh_nomina_novedades.`idPersonaCargo`=:idPersonaCargo AND rh_nomina_novedades_detalle.idLiquidacionNomina =:idLiquidacion ) \n ),\n liquidacion AS (\n\tSELECT rh_nomina_liquidacion_detalle.`VDevengado`\n\t, rh_nomina_conceptos.`Id`  idConcepto, rh_nomina_liquidacion_detalle.`NHora`\n\t, maestra.Id\n\t, maestra.`idPersonaCargo`, maestra.idDetalleNovedad\n\tFROM rh_nomina_liquidacion_detalle\n\tINNER JOIN `rh_nomina_concepto_unidadf` ON (rh_nomina_concepto_unidadf.`Id`=rh_nomina_liquidacion_detalle.`Id_ConceptoCN`)\n\tINNER JOIN `rh_nomina_conceptos` ON (rh_nomina_conceptos.`Id`=rh_nomina_concepto_unidadf.`Id_ConceptosN`)\n\tINNER JOIN maestra ON (maestra.idConcepto=rh_nomina_conceptos.`Id`)\n\tAND  (maestra.`idPersonaCargo`=rh_nomina_liquidacion_detalle.`Id_PersonaC`)\n       AND (maestra.`idLiquidacionNomina`=rh_nomina_liquidacion_detalle.`Id_Liquidacion`)\n ) \n--  select * from liquidacion\n \n SELECT  m.horaInicio \n     ,m.horaFin \n     , m.`fechaD` \n     , m.`cantidad` \n     , m.`porcentaje` \n     , m.fechaInicio \n     , m.fechaFin\n     , m.clasificacionNominaElectronica  \n       ,if(m.`porcentaje` <>0, ((l.VDevengado / l.NHora )* m.`cantidad` ),m.valor) valor\n       , l.VDevengado , l.NHora, m.porcentajeDian\n FROM maestra m\n LEFT JOIN liquidacion l ON  (l.idDetalleNovedad=m.idDetalleNovedad) ", nativeQuery = true)
    List<NovedadesNomina> obtenerNovedadesNomina(@Param("idPersonaCargo") Integer num, @Param("idLiquidacion") Integer num2);

    @Query(value = "SELECT\n    `g_persona`.`NoDocumento` AS noDocumento\n    , `cc_resolucion_dian`.`Prefijo` AS prefijo\n    ,LPAD(`rh_nomina_liquidacion_detalle_1`.`Consecutivo`,5,'0') AS consecutivo\n    , CONCAT(`cc_resolucion_dian`.`Prefijo`,LPAD(`rh_nomina_liquidacion_detalle_1`.`Consecutivo`,5,'0')) AS numero\nFROM\n    `baseserver`.`rh_nomina_liquidacion_detalle` AS `rh_nomina_liquidacion_detalle_1`\n    INNER JOIN `baseserver`.`cc_resolucion_dian` \n        ON (`rh_nomina_liquidacion_detalle_1`.`Id_resolucion` = `cc_resolucion_dian`.`Id`)\n    INNER JOIN `baseserver`.`rh_tipo_persona_cargon` \n        ON (`rh_nomina_liquidacion_detalle_1`.`Id_PersonaC` = `rh_tipo_persona_cargon`.`Id`)\n    INNER JOIN `baseserver`.`g_persona` \n        ON (`rh_tipo_persona_cargon`.`Id_Persona` = `g_persona`.`Id`)\n        WHERE(`rh_nomina_liquidacion_detalle_1`.`Id_PersonaC` =:idPersona AND `rh_nomina_liquidacion_detalle_1`.`Id_Liquidacion` =:liquidacion) LIMIT 1 ", nativeQuery = true)
    INumeroSecuenciaXML obtenerNumeroSecuenciaXML(@Param("idPersona") Integer num, @Param("liquidacion") Integer num2);

    @Query(value = "SELECT\n    `g_empresa`.`Nbre` AS razonSocial\n    , `g_empresa`.`Apellido1` AS primerApellido\n    , `g_empresa`.`Apellido2` AS segundoApellido\n    , `g_empresa`.`Nombre1` AS primerNombre\n    , `g_empresa`.`Nombre2` AS otrosNombres\n    , `g_empresa`.`No_identificacion` AS nit\n    , `g_empresa`.`Dig_Verificacion` AS dv\n    , `g_ips`.idSoftwareNomina AS softwareId\n    , `g_ips`.pinSoftware AS pinSoftware\nFROM\n    `baseserver`.`g_ips`\n    INNER JOIN `baseserver`.`g_empresa` \n        ON (`g_ips`.`Id_gempresa` = `g_empresa`.`Id`);", nativeQuery = true)
    IProveedorXml obtenerProveedorXML();

    @Query(value = "SELECT\n                                                   rh_nomina_liquidacion.FechaR AS fecha  \n                                                  ,rh_nomina_liquidacion_detalle.Id_Liquidacion AS idLiquidacion\n                                                  , rh_nomina_liquidacion_detalle.Id_PersonaC AS idPersona\n                                                  , g_persona.`NoDocumento` AS noDocumento\n                                                  , CONCAT(g_persona.Nombre1, ' ' \n                                                  , g_persona.Nombre2,' '\n                                                  , g_persona.Apellido1,' '\n                                                  , g_persona.Apellido2) AS empleado\n                                                  ,`rh_tipo_persona_cargon`.`FechaIngreso`\n                                                  , DATEDIFF(CURDATE(), `rh_tipo_persona_cargon`.`FechaIngreso`) AS tiempoLaborado\n                                                  , `rh_nomina_liquidacion`.`Id_Periodo` AS idPeriodo   \n                                                  ,`rh_nomina_liquidacion_detalle`.`cune`\n                                                  , `rh_nomina_liquidacion_detalle`.`Consecutivo` as consecutivo                                              FROM\n                                                  rh_nomina_liquidacion_detalle\n                                                  LEFT JOIN `rh_tipo_persona_cargon` \n                                                      ON (rh_nomina_liquidacion_detalle.Id_PersonaC = `rh_tipo_persona_cargon`.Id)\n                                                  LEFT JOIN `g_persona`\n                                                      ON (`rh_tipo_persona_cargon`.`Id_Persona` = `g_persona`.Id)\n                                    INNER JOIN rh_nomina_liquidacion \n                                         ON(rh_nomina_liquidacion.Id = rh_nomina_liquidacion_detalle.Id_Liquidacion)\n                                                  WHERE(rh_nomina_liquidacion_detalle.Id_Liquidacion =:id AND `rh_nomina_liquidacion_detalle`.`cune`IS NOT NULL  )\n                                                   GROUP BY g_persona.`NoDocumento`  ", nativeQuery = true)
    List<EmpleadoPorNomina> listaEmpleadosReportados(@Param("id") Integer num);

    @Query(value = "SELECT\ntipo,ROUND(`valor`) as valor\nFROM\n    `p_valor_moneda`\nWHERE (`fecha` =:fecha \n    AND `tipo` = 'TRM') LIMIT 1 ", nativeQuery = true)
    TRM getTMR(@Param("fecha") String str);

    @Query(value = "SELECT\n    `rh_nomina_liquidacion`.`FechaR` AS fecha\n    , `rh_nomina_liquidacion_detalle`.`cune` AS cune \n    , LPAD(`rh_nomina_liquidacion_detalle`.`Consecutivo`,5,'0') AS numero\n\nFROM\n   `rh_nomina_liquidacion_detalle`\n    INNER JOIN `baseserver`.`rh_nomina_liquidacion` \n        ON (`rh_nomina_liquidacion_detalle`.`Id_Liquidacion` = `rh_nomina_liquidacion`.`Id`)\nWHERE (`rh_nomina_liquidacion_detalle`.`Id_PersonaC` = :idPersona \n    AND `rh_nomina_liquidacion_detalle`.`Id_Liquidacion` = :liquidacion  AND `rh_nomina_liquidacion_detalle`.`cune` IS NOT NULL ) GROUP BY cune ", nativeQuery = true)
    IEliminandoPredecesor getPredecesor(@Param("idPersona") Integer num, @Param("liquidacion") Integer num2);

    @Query(value = "UPDATE `rh_nomina_liquidacion_detalle` \nSET `rh_nomina_liquidacion_detalle`.`cune` = :cune, `rh_nomina_liquidacion_detalle`.keyDian = :keyDian\nWHERE `rh_nomina_liquidacion_detalle`.`Id_Liquidacion` = :idLiquidacion \nAND `rh_nomina_liquidacion_detalle`.`Id_PersonaC` = :idPersona ;", nativeQuery = true)
    void actualizarDatos(@Param("idLiquidacion") String str, @Param("idPersona") String str2, @Param("cune") String str3, @Param("keyDian") String str4);
